import json
import base64
import urllib.request
import urllib.error
import ssl
from urllib.parse import urlparse

DEFAULT_TIMEOUT_SECONDS = 1.5
MAX_URLS = 5
MAX_RESPONSE_BYTES = 64 * 1024
ALLOWED_SCHEMES = {"https"}
ALLOWED_HOST_SUFFIXES = None  # e.g. [".example.com", ".internal.example.com"]


def _get_headers_dict(cf_headers):
    out = {}
    for k, v in (cf_headers or {}).items():
        if v and isinstance(v, list) and len(v) > 0 and "value" in v[0]:
            out[k.lower()] = v[0]["value"]
    return out


def _set_header(cf_headers, name, value):
    cf_headers[name.lower()] = [{"key": name, "value": value}]


def _del_header(cf_headers, name):
    cf_headers.pop(name.lower(), None)


def _parse_urls(header_value):
    if not header_value:
        return []
    parts = [p.strip() for p in header_value.split(",")]
    urls = [p for p in parts if p]
    return urls[:MAX_URLS]


def _is_allowed_url(url):
    try:
        p = urlparse(url)
    except Exception:
        return False, "invalid_url"

    if p.scheme.lower() not in ALLOWED_SCHEMES:
        return False, "scheme_not_allowed"

    if not p.netloc:
        return False, "missing_host"

    host = p.hostname or ""
    if not host:
        return False, "missing_host"

    if ALLOWED_HOST_SUFFIXES:
        ok = any(host == s.lstrip(".") or host.endswith(s) for s in ALLOWED_HOST_SUFFIXES)
        if not ok:
            return False, "host_not_allowed"

    return True, None


def _fetch_url(url, timeout=DEFAULT_TIMEOUT_SECONDS):
    ctx = ssl.create_default_context()
    req = urllib.request.Request(
        url,
        method="GET",
        headers={
            "User-Agent": "lambda-edge-enrichment/1.0",
            "Accept": "application/json, text/plain;q=0.9, */*;q=0.1",
        },
    )
    try:
        with urllib.request.urlopen(req, timeout=timeout, context=ctx) as resp:
            status = getattr(resp, "status", None) or resp.getcode()
            headers = dict(resp.headers.items()) if getattr(resp, "headers", None) else {}
            content_type = headers.get("Content-Type", "")
            raw = resp.read(MAX_RESPONSE_BYTES + 1)
            truncated = len(raw) > MAX_RESPONSE_BYTES
            if truncated:
                raw = raw[:MAX_RESPONSE_BYTES]
            try:
                text = raw.decode("utf-8", errors="replace")
            except Exception:
                text = base64.b64encode(raw).decode("ascii")
                content_type = content_type or "application/octet-stream"
            return {
                "url": url,
                "ok": 200 <= int(status) < 300,
                "status": int(status),
                "contentType": content_type,
                "truncated": truncated,
                "body": text,
            }
    except urllib.error.HTTPError as e:
        try:
            raw = e.read(MAX_RESPONSE_BYTES)
            body = raw.decode("utf-8", errors="replace")
        except Exception:
            body = ""
        return {
            "url": url,
            "ok": False,
            "status": int(getattr(e, "code", 0) or 0),
            "contentType": (e.headers.get("Content-Type", "") if getattr(e, "headers", None) else ""),
            "truncated": False,
            "error": "http_error",
            "body": body,
        }
    except urllib.error.URLError as e:
        return {
            "url": url,
            "ok": False,
            "status": 0,
            "contentType": "",
            "truncated": False,
            "error": "url_error",
            "message": str(getattr(e, "reason", e)),
        }
    except Exception as e:
        return {
            "url": url,
            "ok": False,
            "status": 0,
            "contentType": "",
            "truncated": False,
            "error": "exception",
            "message": str(e),
        }


def handler(event, context):
    record = event["Records"][0]
    cf = record["cf"]
    request = cf["request"]
    headers = request.get("headers", {})

    hdrs = _get_headers_dict(headers)
    enrich_header = hdrs.get("x-enrich-url") or hdrs.get("x-enrich-urls")
    urls = _parse_urls(enrich_header)

    results = []
    for url in urls:
        allowed, reason = _is_allowed_url(url)
        if not allowed:
            results.append({"url": url, "ok": False, "status": 0, "error": reason})
            continue
        results.append(_fetch_url(url))

    if results:
        payload = json.dumps(
            {
                "version": 1,
                "count": len(results),
                "results": results,
            },
            separators=(",", ":"),
        )
        b64 = base64.b64encode(payload.encode("utf-8")).decode("ascii")
        _set_header(headers, "X-Enrich-Context", b64)
        _set_header(headers, "X-Enrich-Context-Format", "base64-json")
        _set_header(headers, "X-Enrich-Context-Count", str(len(results)))

    _del_header(headers, "X-Enrich-URL")
    _del_header(headers, "X-Enrich-URLs")

    request["headers"] = headers
    return request